import { formatUnits } from 'viem';

import type { GlobalFlags } from '@/types';
import type { Network } from '@agentcash/networks';

export const getBaseUrl = (dev: boolean) => {
  return dev ? 'http://localhost:3000' : 'https://agentcash.dev';
};

export const getDepositLink = (
  address: string,
  flags: GlobalFlags,
  network?: Network
) => {
  return `${getBaseUrl(flags.dev)}/deposit/${address}${network ? `?network=${network}` : ''}`;
};

export const tokenStringToNumber = (amount: string, decimals = 6) => {
  return Number(formatUnits(BigInt(amount), decimals));
};

export const formatUsd = (amount: number) => {
  const fractionDigits = amount < 0.01 && amount > 0 ? 4 : 2;
  return amount.toLocaleString('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 2,
    maximumFractionDigits: fractionDigits,
  });
};
